ulu-adaptive-lt.light:
.ulu-adaptive-lt {
--ulu-glass-ring-light: 0 0 0 1px rgba(255, 255, 255, 0.75);
/* outer glow ring on glass elements (light mode) */
--mix-base-dark: #18181b;
/* neutral dark anchor used in colour-mix() calculations */
--mix-base-light: color-mix(
        in srgb,
        var(--color-accent) 3%,
        #fcfcfc
    );
/* neutral light anchor, faint accent bleed into near-white */
--proxy-00: color-mix(
        in srgb,
        var(--color-accent) 6%,
        var(--mix-base-light)
    );
/* raw darkest surface, 6% accent tint */
--proxy-10: color-mix(
        in srgb,
        var(--color-accent) 12%,
        var(--mix-base-light)
    );
/* raw mid surface, 12% accent tint */
--proxy-20: color-mix(
        in srgb,
        var(--color-accent) 9%,
        var(--mix-base-light)
    );
/* raw secondary surface, 9% accent tint */
--color-base-00: var(--proxy-00);
/* deepest background layer */
--color-base-10: var(--proxy-10);
/* primary workspace background */
--color-base-20: var(--proxy-20);
/* secondary / content-well background */
--color-base-25: color-mix(
        in srgb,
        var(--color-accent) 12%,
        white
    );
/* subtle separator and hover surface */
--color-base-30: color-mix(
        in srgb,
        var(--color-accent) 18%,
        white
    );
/* border-adjacent surface */
--color-base-35: color-mix(
        in srgb,
        var(--color-accent) 15%,
        white
    );
/* interactive element background */
--color-base-40: color-mix(
        in srgb,
        var(--color-accent) 22%,
        white
    );
/* active / selected element background */
--background-modifier-border-alt: color-mix(
        in srgb,
        var(--color-accent) 25%,
        white
    );
/* alternate UI border, 25% accent tint */
--mono-rgb-100: #ffffff;
/* pure white highlight anchor */
--mono-rgb-0: color-mix(
        in srgb,
        var(--color-accent) 40%,
        #000000
    );
/* shadow/fill anchor, heavily tinted toward accent */
--color-base-100: var(--mono-rgb-0);
/* primary body text */
--color-base-70: color-mix(
        in srgb,
        var(--color-base-100) 70%,
        transparent
    );
/* secondary body text, 70% of base-100 */
--color-base-50: color-mix(
        in srgb,
        var(--color-base-100) 70%,
        transparent
    );
/* mid-tone — subdued icons and dividers */
--gradient-bg-primary: linear-gradient(
        135deg,
        color-mix(in srgb, var(--proxy-00), var(--color-accent) 10%) 0%,
        var(--proxy-00) 100%
    ) !important;
/* primary pane background gradient, 10% accent bleed at edge */
--gradient-bg-secondary: linear-gradient(
        135deg,
        color-mix(in srgb, var(--proxy-20), var(--color-accent) 15%) 0%,
        var(--proxy-20) 100%
    ) !important;
/* secondary pane background gradient, 15% accent bleed */
--color-base-60: color-mix(
        in srgb,
        var(--color-accent) 50%,
        white
    );
/* muted text, half-accent half-white */
--background-modifier-form-field: var(
        --color-base-25
    );
/* input / field background */
--background-modifier-form-field-highlighted: var(
        --color-base-35
    );
/* highlighted form field background */
--background-modifier-box-shadow: rgb(
        from var(--mono-rgb-0) r g b / 0.1
    );
/* box shadow tint colour */
--background-modifier-cover: rgb(
        from var(--mono-rgb-0) r g b / 0.2
    );
/* modal overlay scrim colour */
--text-on-accent: #ffffff;
/* text rendered on accent-coloured backgrounds */
--text-on-accent-inverted: #000000;
/* inverted variant of text-on-accent */
--icon-color: var(--text-muted);
/* default icon colour */
--icon-color-hover: var(--text-normal);
/* icon colour on hover */
--icon-color-active: var(
        --color-accent
    );
/* icon colour when active / selected */
--color-green: #8fbc8f;
--color-green-hsl: 120, 25%, 65%;
--color-green-rgb: 143, 188, 143;
}

